import { test, expect } from '@playwright/test';

test('Amazon SG - Search and validate laptop stand product title', async ({ page }) => {
  // 1. Launch browser and navigate to Amazon SG
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "laptop stand"
  const searchBox = page.locator('input[name="field-keywords"]');
  await expect(searchBox).toBeVisible();
  await searchBox.fill('laptop stand');
  await page.locator('input#nav-search-submit-button').click();

  // 3. Click on first product
  const firstProduct = page.locator('a[href*="/dp/"]').first();
  await expect(firstProduct).toBeVisible();
  await firstProduct.click();

  // 4. Wait for product title (visible span, not hidden input)
  const productTitle = page.locator('span#productTitle');
  await expect(productTitle).toBeVisible({ timeout: 10000 });

  // 5. Validate product title is visible
  await expect(productTitle).toBeVisible();

  // 6. Close browser (handled automatically by Playwright)
});
